INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('public-health-specialist-moex-00577', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '為適當維護全民健康保險資源之運用，全民健康保險法及全民健康保險醫療辦法允許保險人 採行何種措施？', '["保險對象有重複就醫或不當利用醫療資源之情形者，保險人應予以輔導，瞭解其就醫原因、 提供適當醫療衛教、安排就醫及給予必要之協助。就醫輔導得以郵寄關懷函、電訪、訪視、 運用相關社會資源或其他方式進行，必要時得公布保險對象身分", "保險人對門診高利用保險對象，得依其病情，指定其至特定之保險醫事服務機構接受診療 服務。保險對象未依保險人輔導，於指定之保險醫事服務機構就醫者，除事前報經保險人 同意者外，保險人得不予給付", "醫療服務及藥物屬高危險、昂貴或有不當使用之虞者，應於使用前報經保險人審查同意。 但情況緊急或屬醫療資源缺乏地區者，不在此限", "保險人得辦理醫療科技評估，考量人體健康、醫療倫理、醫療成本效益及財務狀況，訂定 醫療服務給付項目及支付標準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00578', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '有關傳染病防治法對於通報、提供資料及採行措施之規範，下列敘述何者錯誤？', '["各類法定傳染疾病一經發現，主管機關應於收到通報後二十四小時內將罹病病人送至指定 隔離治療機構施行隔離治療", "中央主管機關為控制流行疫情，得公布因傳染病或疫苗接種死亡之資料", "嚴重特殊傳染性肺炎（COVID-19）為第四類傳染病，醫師發現病例時，應依中央主管機關 公告之期限及規定方式通報主管機關", "主管機關得要求醫事機構提供傳染病病人或疑似疫苗接種後產生不良反應個案之就醫紀 錄、病歷、相關檢驗結果、治療情形及解剖鑑定報告等資料"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00579', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '下列關於公共衛生師法就公共衛生師之資格與執業規範，何者正確？', '["為促進公共衛生專業服務體系，中華民國國民或領有居留證之外國人參加並通過公共衛生 師考試，得請領公共衛生師證書，執行公共衛生師業務", "因突發緊急或重大公共衛生事件，主管機關得指定公共衛生師辦理環境健康風險、疾病調 查及防治等業務，因此所生之費用或損失，得請求主管機關給予相當之補償", "醫事、健康照護或長期照護機構應聘用公共衛生師，執行場域環境健康、疾病調查及健康 促進之規劃、推動或評估", "領有公共衛生師證書或醫事人員經受聘於依法規應進用公共衛生師之機關、機構者，始得 使用公共衛生師名稱"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00580', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '依據環境影響評估法規定，開發行為對環境有不良影響之虞者，應實施環境影響評估，下列 何者非屬環境影響評估作業程序之規範內容？', '["開發單位申請許可開發行為時，應向目的事業主管機關提出環境影響說明書", "目的事業主管機關應將環境影響說明書轉送主管機關審查，由主管機關於五十日內作成審 查結論", "主管機關審查結論認為不須進行第二階段環境影響評估並經許可者，開發單位應舉行公開 之說明會", "開發單位舉行公開說明會前，若不立即開發有發生災害之虞者，目的事業主管機關得先行 許可開發行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00581', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '以下有關公共衛生師法之敘述，何者正確？', '["公共衛生師執業，應加入執業登記處所所在地公共衛生師公會", "公共衛生師執行業務所製作紀錄及報告，應至少保存六年", "因公共衛生師不得洩漏因業務所知悉或持有他人之秘密，故在有關機關詢問時得拒絕陳述 或報告", "為確保公共衛生師執業品質，公共衛生師執業僅能受聘於醫事、健康照護或長期照顧機構、 公共衛生師事務所及其他經主管機關認可之機構或場所，不得以支援為理由於其他機構或 場所執業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00582', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '以下有關二代全民健康保險之改革內容，何者敘述錯誤？', '["將監理委員會與醫療費用協定委員會整合為全民健康保險委員會", "全民健康保險費之收取改採雙軌制，除一般保險費之外，另計高額獎金、兼職薪資、執行 業務所得、股利所得、利息所得、租金所得等收入計收補充保險費", "醫療服務與藥物之給付項目及支付標準，由專家學者、被保險人、雇主、保險醫事服務提 供者等多元代表共同決定之決策模式，改為以專家學者為主之決策模式", "全民健康保險會之業務內容除保險醫療給付費用總額之對等協議訂定及分配、與保險費率 之審議外，亦包括保險給付範圍之審議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00583', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '以下有關藥事法之敘述，何者錯誤？', '["藥商製造或輸入學名藥，除應申請中央衛生主管機關查驗登記外，尚應就參考新藥藥品許 可證所有人已核准新藥所登載之專利權作出相關聲明", "醫師得依自開處方親自為藥品調劑之行為，僅限於中央或直轄市衛生主管機關公告無藥事 人員執業之偏遠地區或醫療急迫情形", "有關醫療器材之管理應同時依照藥事法與醫療器材管理法之規定", "依藥事法第44條規定，試驗用藥物僅得提供於核可之教學醫院臨床試驗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00584', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '以下有關臺灣食品安全衛生管理法食品安全三級品管之制度敘述，何者正確？', '["上市、上櫃食品業者應實施自主管理，並訂定食品安全監測計畫，以確保食品衛生安全", "所有食品業者均應設置實驗室以從事自主檢驗", "食品安全管制系統準則僅強制適用於中央主管機關公告類別及規模之食品業", "為有效遏止廠商之違法行為，主管機關於執行現場查核及抽樣檢驗時具有警察權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00585', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '以下有關2023年菸害防制法修法之敘述，何者正確？', '["加熱菸與電子煙均屬於中央主管機關公告指定之菸品，業者應向中央主管機關申請健康風 險評估審查並經核定通過後，始得製造或輸入", "加熱菸之組合元件（如載具）因不含菸草或含有尼古丁之天然植物，不屬於菸害防制法所 定義之菸品，故不受菸品不得以開放式貨架、自動販賣、郵購或電子購物販賣之限制", "菸品容器最大正面及反面明顯位置處標示警示圖文及戒菸相關資訊之面積，增加至85%", "因菸品不得使用經中央主管機關公告禁止使用之添加物，故加味菸將納入菸害防制法之規範"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00586', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '以下有關2022年全文修正精神衛生法之敘述，何者正確？', '["社區支持服務與個案管理並未納入精神醫療照護與支持服務體系", "警消協助就醫之規定，僅限患精神疾病，並已有傷害他人或自己情事者，且限非管束不能 救護其生命身體之危險、或預防他人生命身體之危險時", "嚴重病人傷害他人或自己或有傷害之虞者，經二位以上專科醫師強制鑑定有全日住院治療 之必要，且通過中央主管機關精神疾病強制鑑定、強制社區治療審查會之審查許可，便可 啟動強制住院程序", "嚴重病人緊急安置期間，未經委任律師為代理人者，應由精神醫療機構通報中央主管機關 提供必要之法律扶助"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
